import React, { useEffect, useState } from "react";
import { useSelector, useDispatch } from "react-redux";
import { motion, AnimatePresence } from "framer-motion";
import { Link } from "react-router-dom";
import { fetchLessons } from "../store/slices/lessonSlice";

import Navbar from "../components/Common/Navbar";
import StreakCalendar from "../components/Dashboard/StreakCalendar";

const Dashboard = () => {
  const dispatch = useDispatch();
  const { user } = useSelector((state) => state.auth);
  const { lessons = [], loading } = useSelector((state) => state.lesson);

  const [greeting, setGreeting] = useState("");
  const [activeTab, setActiveTab] = useState("all");

  useEffect(() => {
    dispatch(fetchLessons());

    const hour = new Date().getHours();
    if (hour < 12) setGreeting("Good Morning");
    else if (hour < 17) setGreeting("Good Afternoon");
    else setGreeting("Good Evening");
  }, [dispatch]);

  const stats = [
    {
      label: "Total XP",
      value: user?.xp_points || 0,
      icon: "⚡",
    },
    {
      label: "Current Level",
      value: user?.level || 1,
      icon: "🏆",
    },
    {
      label: "Day Streak",
      value: user?.streak_days || 0,
      icon: "🔥",
    },
    {
      label: "Signs Mastered",
      value: user?.total_signs_learned || 0,
      icon: "✋",
    },
  ];

  const lessonTabs = [
    { id: "all", label: "All Lessons" },
    { id: "progress", label: "In Progress" },
    { id: "completed", label: "Completed" },
  ];

  const filteredLessons = lessons.filter((lesson) => {
    if (activeTab === "all") return true;
    if (activeTab === "progress") return lesson.progress > 0 && lesson.progress < 100;
    if (activeTab === "completed") return lesson.progress === 100;
    return true;
  });

  return (
    <div className="min-h-screen w-full bg-[#0a0a0f] text-white">

      <Navbar />

      <div className="relative w-full max-w-7xl mx-auto px-6 py-8">

        {/* Greeting */}
        <div className="mb-10">
          <p className="text-gray-400">{greeting} 👋</p>

          <h1 className="text-4xl font-bold mt-2">
            Namaste, {user?.full_name?.split(" ")[0] || "Learner"}!
          </h1>

          <div className="flex gap-3 mt-3">
            <span className="bg-orange-500/20 px-3 py-1 rounded-full text-sm">
              🔥 {user?.streak_days || 0} Day Streak
            </span>

            <span className="bg-purple-500/20 px-3 py-1 rounded-full text-sm">
              🎯 Level {user?.level || 1}
            </span>
          </div>
        </div>

        {/* Stats */}
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-10">
          {stats.map((stat, i) => (
            <div
              key={i}
              className="bg-white/5 p-5 rounded-xl border border-white/10"
            >
              <div className="text-2xl">{stat.icon}</div>
              <div className="text-2xl font-bold mt-2">{stat.value}</div>
              <div className="text-gray-400 text-sm">{stat.label}</div>
            </div>
          ))}
        </div>

        {/* Main grid */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">

          {/* Lessons */}
          <div className="lg:col-span-2 space-y-6">

            <div className="flex justify-between items-center">
              <h2 className="text-2xl font-bold">📚 Continue Learning</h2>

              <div className="flex gap-2">
                {lessonTabs.map((tab) => (
                  <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id)}
                    className={`px-4 py-2 rounded-lg text-sm ${
                      activeTab === tab.id
                        ? "bg-purple-600"
                        : "bg-white/5 hover:bg-white/10"
                    }`}
                  >
                    {tab.label}
                  </button>
                ))}
              </div>
            </div>

            <AnimatePresence mode="wait">
              {loading ? (
                <div className="text-gray-400">Loading lessons...</div>
              ) : (
                <div className="space-y-4">
                  {filteredLessons.map((lesson) => (
                    <Link
                      key={lesson.id}
                      to={`/lesson/${lesson.id}`}
                      className="block text-white"
                    >
                      <motion.div
                        whileHover={{ scale: 1.02 }}
                        className="bg-white/5 p-5 rounded-xl border border-white/10"
                      >
                        <h3 className="text-lg font-semibold">
                          {lesson.title}
                        </h3>

                        <p className="text-gray-400 text-sm">
                          {lesson.description}
                        </p>

                        <div className="text-sm text-purple-400 mt-2">
                          Progress: {lesson.progress || 0}%
                        </div>
                      </motion.div>
                    </Link>
                  ))}
                </div>
              )}
            </AnimatePresence>
          </div>

          {/* Sidebar */}
          <div className="space-y-6">

            {/* Level Progress */}
            <div className="bg-white/5 p-5 rounded-xl border border-white/10">
              <h3 className="text-lg font-semibold mb-3">⚡ Level Progress</h3>

              <div className="h-3 bg-white/10 rounded-full overflow-hidden">
                <div
                  className="h-full bg-purple-500"
                  style={{ width: `${(user?.xp_points || 0) % 100}%` }}
                />
              </div>

              <p className="text-sm text-gray-400 mt-2">
                {(user?.xp_points || 0)} XP
              </p>
            </div>

            {/* Streak Calendar */}
            <div className="bg-white/5 p-4 rounded-xl border border-white/10">
              <StreakCalendar streakDays={user?.streak_days || 0} />
            </div>

            {/* Practice */}
            <Link to="/practice">
              <button className="w-full bg-purple-600 hover:bg-purple-700 py-4 rounded-xl font-semibold">
                📷 Practice with Webcam
              </button>
            </Link>

          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
